## 代码实现模板

```cpp
#include <bits/stdc++.h>
using namespace std;

int main()
{
    // 1. 声明与初始化
    vector<int> v; // 创建空容器

    // 2. 增加元素
    v.push_back(10); 
    v.push_back(20);

    // 3. 获取大小
    int n = v.size();

    // 4. 访问元素 (下标方式)
    if (!v.empty()) 
    {
        v[0] = 100;
    }

    // 5. 遍历方式 A: 下标遍历
    for (int i = 0; i < v.size(); i++)
    {
        // cout << v[i] << endl;
    }

    // 6. 遍历方式 B: 迭代器遍历 (Level 5 重点)
    for (vector<int>::iterator it = v.begin(); it != v.end(); ++it)
    {
        // *it 就像指针解引用，获取当前位置的值
        cout << *it << " ";
    }

    // 7. 常用算法
    sort(v.begin(), v.end()); // 升序
    reverse(v.begin(), v.end()); // 翻转

    // 8. 清空
    v.clear();

    return 0;
}
```

