## 代码示例  
```cpp
#include <bits/stdc++.h>
using namespace std;

int main()
{
    long long n;
    // 输入待分解的数
    cin >> n;

    // 存储质因数及其个数
    long long fac[30];
    int cnt[30];
    int k = 0;
    // 初始化计数
    for (int i = 0; i < 30; i++)
    {
        cnt[i] = 0;
    }

    // 试除法分解
    for (long long i = 2; i * i <= n; i++)
    {
        // 如果 i 是 n 的质因数
        while (n % i == 0)
        {
            fac[k] = i;      // 记录质因数 i
            cnt[k]++;        // 对应因数个数加一
            n /= i;          // 除去已分解的因数
        }
        if (cnt[k] > 0)
        {
            k++;             // 移动到下一个存储位置
        }
    }

    // 如果剩下的 n > 1，则它本身也是质因数
    if (n > 1)
    {
        fac[k] = n;
        cnt[k] = 1;
        k++;
    }

    // 输出结果
    for (int i = 0; i < k; i++)
    {
        cout << fac[i];
        if (cnt[i] > 1)
        {
            cout << "^" << cnt[i];
        }
        if (i + 1 < k)
        {
            cout << " * ";
        }
    }
    cout << endl;

    return 0;
}
```

