## 代码示例

### 1. 埃拉托斯特尼筛法 (Sieve of Eratosthenes)

```cpp
#include <bits/stdc++.h>
using namespace std;

const int N_MAX = 1000005; // 定义最大范围 N
bool v[N_MAX];             // v[i] 为 true 表示 i 是合数，false 表示 i 是质数
int p[N_MAX / 6];          // 存储质数的数组，N/ln(N) 大约是质数数量的上限

void sieve_eratosthenes(int n) {
    // 初始化，所有数默认是质数 (除了0和1，它们不参与筛法)
    // v[0] = v[1] = true; // 0和1不是质数，但我们通常从2开始筛
    int cnt = 0; // 记录找到的质数数量

    for (int i = 2; i <= n; ++i) {
        if (!v[i]) { // 如果 i 是质数 (未被标记为合数)
            p[cnt++] = i; // 记录下这个质数
        }
        // 标记 i 的所有倍数为合数
        // 从 i*i 开始优化，因为 2*i, 3*i, ... (k-1)*i 已经被 k 的质因子标记过了
        // 例如，4的倍数2*4=8，在2筛的时候就被标记了
        // 实际上，从 2*i 开始也可以，但会做更多重复标记
        for (long long j = (long long)i * i; j <= n; j += i) {
            v[j] = true; // 标记为合数
        }
    }
    // 另一种更常见的埃氏筛写法，从 k*i 开始标记，避免重复判断i是否为质数，直接从2开始循环
    // 这种写法下，外层循环到 sqrt(n) 即可
    /*
    for (int i = 2; i <= n; ++i) {
        if (!v[i]) { // 如果 i 是质数
            p[cnt++] = i;
            // 标记 i 的所有倍数为合数
            // 从 2*i 开始，因为 i 本身是质数
            for (long long j = (long long)i * 2; j <= n; j += i) {
                v[j] = true;
            }
        }
    }
    */
    // 更优化的埃氏筛写法，外层循环到 sqrt(n)
    // 并且只用质数去筛，而不是所有数
    // 但这里为了简化理解，我们用第一个版本，或者下面的线性筛
    // 实际上，最常见的埃氏筛是：
    fill(v, v + n + 1, false); // 全部初始化为 false (质数)
    cnt = 0; // 重置质数计数
    for (int i = 2; i <= n; ++i) {
        if (!v[i]) { // 如果 i 没有被标记过，说明 i 是质数
            p[cnt++] = i; // 记录这个质数
            // 标记 i 的所有倍数为合数
            // 从 i*i 开始标记可以避免重复，因为小于 i*i 的倍数已经被更小的质数标记过了
            // 例如，对于 i=5，2*5=10 已经在 i=2 时被标记了，3*5=15 已经在 i=3 时被标记了
            for (long long j = (long long)i * i; j <= n; j += i) {
                if (!v[j]) { // 避免重复标记，虽然不加也行
                    v[j] = true;
                }
            }
        }
    }


    cout << "埃氏筛法找到的质数 (前10个): ";
    for (int i = 0; i < min(10, cnt); ++i) {
        cout << p[i] << " ";
    }
    cout << endl;
    cout << "1到" << n << "之间共有 " << cnt << " 个质数。" << endl;
}

// int main() {
//     sieve_eratosthenes(100); // 找出100以内的所有质数
//     return 0;
// }

```

### 2. 线性筛法 (Linear Sieve / Euler Sieve)

```cpp
#include <bits/stdc++.h>
using namespace std;

const int N_MAX = 1000005; // 定义最大范围 N
bool v[N_MAX];             // v[i] 为 true 表示 i 是合数，false 表示 i 是质数
int p[N_MAX / 6];          // 存储质数的数组，N/ln(N) 大约是质数数量的上限
int cnt;                   // 记录找到的质数数量

void sieve_linear(int n) {
    fill(v, v + n + 1, false); // 初始化，所有数默认是质数 (false)
    cnt = 0; // 重置质数计数

    for (int i = 2; i <= n; ++i) {
        if (!v[i]) { // 如果 i 是质数 (未被标记为合数)
            p[cnt++] = i; // 记录下这个质数
        }

        // 用当前找到的质数 p[j] 去筛掉 i * p[j]
        for (int j = 0; j < cnt && (long long)i * p[j] <= n; ++j) {
            v[i * p[j]] = true; // 标记 i * p[j] 为合数

            // 关键优化：如果 i 能被 p[j] 整除，说明 p[j] 是 i 的最小质因子
            // 那么 i * p[j+1], i * p[j+2]... 这些合数的最小质因子也都是 p[j]
            // 例如 i=6, p[j]=2, 标记12。因为6%2==0，所以6*3=18的最小质因子是2，而不是3。
            // 18会在i=9, p[j]=2时被标记。
            // 为了保证每个合数只被其最小质因子标记一次，这里需要break。
            if (i % p[j] == 0) {
                break;
            }
        }
    }

    cout << "线性筛法找到的质数 (前10个): ";
    for (int i = 0; i < min(10, cnt); ++i) {
        cout << p[i] << " ";
    }
    cout << endl;
    cout << "1到" << n << "之间共有 " << cnt << " 个质数。" << endl;
}

int main() {
    cout << "--- 埃氏筛法 ---" << endl;
    sieve_eratosthenes(100000); // 找出10万以内的所有质数
    cout << endl;
    cout << "--- 线性筛法 ---" << endl;
    sieve_linear(100000); // 找出10万以内的所有质数
    return 0;
}

```

