## 代码示例

```cpp
#include <bits/stdc++.h>
using namespace std;

// 计算 a mod n，结果始终为 [0, n-1]
int mod(int a, int n)
{
    int r = a % n;
    if (r < 0)
    {
        r += n;
    }
    return r;
}

// 判断 a 与 b 是否同余（mod n）
bool isCongruent(int a, int b, int n)
{
    // 若 (a - b) mod n == 0，则同余
    return mod(a - b, n) == 0;
}

// 计算 (a * b) mod n，避免中间溢出
int mulMod(int a, int b, int n)
{
    long long res = 0;
    long long aa = mod(a, n);
    long long bb = mod(b, n);
    // 通过加法模拟乘法，适合大数
    for (int i = 0; i < bb; i++)
    {
        res = mod(res + aa, n);
    }
    return (int)res;
}

int main()
{
    int a, b, n;
    // 示例：判断 17 与 2 是否同余于 5
    a = 17;
    b = 2;
    n = 5;
    if (isCongruent(a, b, n))
    {
        cout << a << " ≡ " << b << " (mod " << n << ")" << endl;
    }
    else
    {
        cout << a << " !≡ " << b << " (mod " << n << ")" << endl;
    }

    // 示例：计算 (7 * 9) mod 5
    cout << "(7 * 9) mod 5 = " << mulMod(7, 9, 5) << endl;

    return 0;
}
```

