## 代码示例  
```cpp
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1005;
int n, m, q;
long long a[MAXN][MAXN];     // 原始数组（可选用于验证）
long long D[MAXN][MAXN];     // 差分数组
long long S[MAXN][MAXN];     // 前缀和数组

int main()
{
    // 输入行列数和操作数
    cin >> n >> m >> q;

    // 初始化差分数组为 0
    for (int i = 1; i <= n + 1; i++)
    {
        for (int j = 1; j <= m + 1; j++)
        {
            D[i][j] = 0;
        }
    }

    // 读取 q 次操作
    // op = 1 表示区域更新，op = 2 表示区域查询（离线示例）
    for (int t = 0; t < q; t++)
    {
        int op, x1, y1, x2, y2;
        long long v;
        cin >> op;
        if (op == 1)
        {
            cin >> x1 >> y1 >> x2 >> y2 >> v;
            // 差分更新
            D[x1][y1]       += v;
            D[x2 + 1][y1]   -= v;
            D[x1][y2 + 1]   -= v;
            D[x2 + 1][y2 + 1] += v;
        }
        else if (op == 2)
        {
            // 离线查询：先构造好前缀和再回答
        }
    }

    // 恢复原始数组：对差分数组做二维前缀和
    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            S[i][j] = D[i][j] + S[i - 1][j] + S[i][j - 1] - S[i - 1][j - 1];
        }
    }

    // 示例：输出恢复后的数组
    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            cout << S[i][j] << " ";
        }
        cout << "\n";
    }

    return 0;
}
```

