## 代码实现模板

```cpp
#include <bits/stdc++.h>
using namespace std;

/*
 * set 二分查找通用模板
 * 适用场景：动态维护有序集合，频繁查询前驱后继
 */

int main()
{
    set<int> s;
    int x;

    // 1. 查找第一个 >= x 的元素 (Lower Bound)
    set<int>::iterator it1 = s.lower_bound(x);
    if (it1 != s.end())
    {
        // 找到了，值为 *it1
    }
    else
    {
        // 集合中所有数都比 x 小
    }

    // 2. 查找第一个 > x 的元素 (Upper Bound)
    set<int>::iterator it2 = s.upper_bound(x);

    // 3. 查找第一个 < x 的元素 (前驱)
    set<int>::iterator it3 = s.lower_bound(x);
    if (it3 != s.begin())
    {
        it3--;
        // 此时 *it3 是最大的比 x 小的数
    }

    return 0;
}
```

