## 代码实现模板

```cpp
#include <bits/stdc++.h>
using namespace std;

/*
 * 函数名：getNextPermutation
 * 功能：将数组 a 修改为字典序的下一个排列
 * 参数：a[] 数组, n 长度
 * 返回值：bool (true 表示存在下一个，false 表示已是最大排列)
 */
bool getNextPermutation(int a[], int n)
{
    // 1. 寻找转折点：从右往左找第一个 a[i] < a[i+1]
    int i = n - 2;
    while (i >= 0 && a[i] >= a[i + 1])
    {
        i--;
    }

    // 如果找不到，说明已经是最大的降序排列
    if (i < 0)
    {
        return false;
    }

    // 2. 寻找替换者：从右往左找第一个比 a[i] 大的数
    int j = n - 1;
    while (a[j] <= a[i])
    {
        j--;
    }

    // 3. 交换
    swap(a[i], a[j]);

    // 4. 反转后缀：将 i 之后的部分变为升序
    int l = i + 1;
    int r = n - 1;
    while (l < r)
    {
        swap(a[l], a[r]);
        l++;
        r--;
    }

    return true;
}
```

