## 代码实现模板

### 数组模拟栈模板（性能更高）
```cpp
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
int st[MAXN]; // 数组模拟栈
int top_idx = 0; // 栈顶指针，0表示空栈

// 入栈
void push(int x)
{
    st[++top_idx] = x;
}

// 出栈
void pop()
{
    if (top_idx > 0) top_idx--;
}

// 查询栈顶
int top()
{
    return st[top_idx];
}

// 判空
bool empty()
{
    return top_idx == 0;
}

// 栈大小
int size()
{
    return top_idx;
}

int main()
{
    // 使用示例
    push(10);
    push(20);
    cout << top() << endl; // 输出 20
    pop();
    cout << top() << endl; // 输出 10
    return 0;
}
```

