1.  **双端队列 (Deque) 简化版：**
    ```cpp
    #include <bits/stdc++.h>

    const int MAXN = 1005; 
    int d[MAXN]; // 使用数组存储Deque元素
    int f = 0;   // 队头指针
    int r = 0;   // 队尾指针

    // 判断队列是否为空
    bool isEmpty() {
        return f == r;
    }

    // 判断队列是否已满
    // 同样牺牲一个空间，或者使用count变量
    bool isFull() {
        return (r + 1) % MAXN == f;
    }

    // 从队尾入队 (push_back)
    void push_back(int x) {
        if (isFull()) {
            std::cout << "Error: Deque is full, cannot push_back " << x << std::endl;
            return;
        }
        d[r] = x;
        r = (r + 1) % MAXN;
    }

    // 从队头入队 (push_front)
    void push_front(int x) {
        if (isFull()) {
            std::cout << "Error: Deque is full, cannot push_front " << x << std::endl;
            return;
        }
        // 队头指针向前移动一位，需要处理负数情况
        f = (f - 1 + MAXN) % MAXN; 
        d[f] = x;
    }

    // 从队头出队 (pop_front)
    int pop_front() {
        if (isEmpty()) {
            std::cout << "Error: Deque is empty, cannot pop_front." << std::endl;
            return -1;
        }
        int val = d[f];
        f = (f + 1) % MAXN;
        return val;
    }

    // 查看队头元素 (get_front)
    int get_front() {
        if (isEmpty()) {
            std::cout << "Error: Deque is empty, no front element." << std::endl;
            return -1;
        }
        return d[f];
    }

