    ```cpp
    #include <bits/stdc++.h>
    using namespace std;

    bool isPalindrome(string s) {
        deque<char> d;
        for (char c : s) {
            if (isalpha(c)) { // 只处理字母
                d.push_back(tolower(c)); // 转换为小写
            }
        }

        while (d.size() > 1) {
            if (d.front() != d.back()) {
                return false;
            }
            d.pop_front();
            d.pop_back();
        }
        return true;
    }

    int main() {
        string s1 = "madam";
        string s2 = "level";
        string s3 = "hello";
        string s4 = "A man, a plan, a canal: Panama";

        cout << "\"" << s1 << "\" is palindrome? " << (isPalindrome(s1) ? "true" : "false") << endl;
        cout << "\"" << s2 << "\" is palindrome? " << (isPalindrome(s2) ? "true" : "false") << endl;
        cout << "\"" << s3 << "\" is palindrome? " << (isPalindrome(s3) ? "true" : "false") << endl;
        cout << "\"" << s4 << "\" is palindrome? " << (isPalindrome(s4) ? "true" : "false") << endl;

