## 代码实现模板

```cpp
#include <bits/stdc++.h>
using namespace std;

/*
 * 堆操作标准模板 (以小根堆为例)
 * 数组下标从 1 开始
 */
const int N = 100010;
int h[N], s;

// 下沉操作：用于删除堆顶或建堆
void down(int p)
{
    int t = p;
    if (p * 2 <= s && h[p * 2] < h[t]) t = p * 2;
    if (p * 2 + 1 <= s && h[p * 2 + 1] < h[t]) t = p * 2 + 1;
    if (t != p)
    {
        swap(h[p], h[t]);
        down(t);
    }
}

// 上浮操作：用于插入新元素
void up(int p)
{
    while (p / 2 >= 1 && h[p] < h[p / 2])
    {
        swap(h[p], h[p / 2]);
        p /= 2;
    }
}

// 线性建堆：从最后一个非叶子节点开始下沉
// 时间复杂度 O(n)
void build(int n)
{
    s = n;
    for (int i = n / 2; i >= 1; i--)
    {
        down(i);
    }
}
```

