## 代码实现模板

```cpp
#include <bits/stdc++.h>
using namespace std;

/*
 * 优先队列（堆）手写模板
 * 适用场景：需要极高性能、或需要修改堆中任意元素（配合映射数组）
 */
struct Heap
{
    int a[100005];
    int n;

    Heap() { n = 0; }

    // 插入元素
    void push(int x)
    {
        a[++n] = x;
        int i = n;
        while (i > 1 && a[i] > a[i / 2]) // 大顶堆逻辑
        {
            swap(a[i], a[i / 2]);
            i /= 2;
        }
    }

    // 弹出堆顶
    void pop()
    {
        a[1] = a[n--];
        int i = 1;
        while (i * 2 <= n)
        {
            int j = i * 2;
            if (j + 1 <= n && a[j + 1] > a[j]) j++;
            if (a[i] >= a[j]) break;
            swap(a[i], a[j]);
            i = j;
        }
    }

    int top() { return a[1]; }
    bool empty() { return n == 0; }
};
```

