### 编程练习答案

**基础题：二叉树的叶子节点计数**

```cpp
#include <bits/stdc++.h>
using namespace std;

struct Node {
    int v;
    Node* l;
    Node* r;

    Node(int val) {
        v = val;
        l = nullptr;
        r = nullptr;
    }
};

// 函数：计算二叉树的叶子节点数量
int countLeaves(Node* root) {
    // 如果根节点为空，没有叶子节点
    if (root == nullptr) {
        return 0;
    }
    // 如果当前节点是叶子节点 (左右子节点都为空)，则返回 1
    if (root->l == nullptr && root->r == nullptr) {
        return 1;
    }
    // 否则，递归计算左右子树的叶子节点数之和
    return countLeaves(root->l) + countLeaves(root->r);
}

int main() {
    // 构建示例二叉树
    Node* n1 = new Node(1);
    Node* n2 = new Node(2);
    Node* n3 = new Node(3);
    Node* n4 = new Node(4);
    Node* n5 = new Node(5);
    Node* n6 = new Node(6);

    n1->l = n2;
    n1->r = n3;
    n2->l = n4;
    n2->r = n5;
    n4->l = n6;

    cout << "叶子节点数量: " << countLeaves(n1) << endl; // 预期输出 3

    // 实际中需要更完善的内存释放
    return 0;
}
```

**进阶题：判断是否为满二叉树**

```cpp
#include <bits/stdc++.h>
using namespace std;

struct Node {
    int v;
    Node* l;
    Node* r;

    Node(int val) {
        v = val;
        l = nullptr;
        r = nullptr;
    }
};

// 辅助函数：计算二叉树的高度
int getHeight(Node* root) {
    if (root == nullptr) {
        return -1; // 空树高度为 -1
    }
    return max(getHeight(root->l), getHeight(root->r)) + 1;
}

// 辅助函数：计算二叉树的节点总数
int countNodes(Node* root) {
    if (root == nullptr) {
        return 0;
    }
    return 1 + countNodes(root->l) + countNodes(root->r);
}

// 函数：判断是否为满二叉树
bool isFullBinaryTree(Node* root) {
    // 空树也是满二叉树 (或根据具体定义，也可以认为不是，这里按节点数0的高度-1是满二叉树处理)
    // 但通常我们讨论的是非空树
    if (root == nullptr) {
        return true;
    }

    int h = getHeight(root); // 计算树的高度
    int n = countNodes(root); // 计算树的节点总数

    // 满二叉树的节点数 n = 2^(h+1) - 1
    // 这里使用位运算 1 << (h + 1) 来计算 2 的 (h+1) 次方
    return n == ((1 << (h + 1)) - 1);
}

int main() {
    // 示例 1: 满二叉树
    //        1
    //       / \
    //      2   3
    //     / \ / \
    //    4  5 6  7
    Node* m1 = new Node(1);
    Node* m2 = new Node(2);
    Node* m3 = new Node(3);
    Node* m4 = new Node(4);
    Node* m5 = new Node(5);
    Node* m6 = new Node(6);
    Node* m7 = new Node(7);

    m1->l = m2; m1->r = m3;
    m2->l = m4; m2->r = m5;
    m3->l = m6; m3->r = m7;

    cout << "示例 1 (满二叉树): " << (isFullBinaryTree(m1) ? "是" : "否") << endl; // 预期输出 是

    // 示例 2: 不是满二叉树 (但可能是完全二叉树)
    //        1
    //       / \
    //      2   3
    //     /
    //    4
    Node* c1 = new Node(1);
    Node* c2 = new Node(2);
    Node* c3 = new Node(3);
    Node* c4 = new Node(4);

    c1->l = c2; c1->r = c3;
    c2->l = c4;

    cout << "示例 2 (非满二叉树): " << (isFullBinaryTree(c1) ? "是" : "否") << endl; // 预期输出 否

    // 示例 3: 只有一个根节点 (也是满二叉树，高度0，节点1，1 = 2^(0+1)-1)
    Node* s1 = new Node(10);
    cout << "示例 3 (单个节点): " << (isFullBinaryTree(s1) ? "是" : "否") << endl; // 预期输出 是

    // 实际中需要更完善的内存释放
    return 0;
}
```

