## 代码实现模板

```cpp
#include <iostream> // 输入输出
#include <string>   // 字符串操作
#include <queue>    // 优先队列 (Priority Queue)
#include <map>      // 映射 (Map)
#include <vector>   // 优先队列的底层容器

// 为了遵守 GESP 规范的简洁变量名，我们对结构体和函数名也进行简化。
// 注意：在实际工程中，结构体和函数名应更具描述性。

// 哈夫曼树节点结构体
struct N
{
    char c;         // 字符本身，如果是内部节点则为 '\0'
    int f;          // 频率 (frequency)
    N *l, *r;       // 左孩子 (left child) 和 右孩子 (right child) 指针

    // 构造函数：用于叶子节点
    N(char character, int frequency)
    {
        c = character;
        f = frequency;
        l = r = nullptr; // 初始化左右孩子为空
    }

    // 构造函数：用于内部节点，合并两个子节点
    N(N* leftChild, N* rightChild)
    {
        c = '\0'; // 内部节点不代表具体字符
        f = leftChild->f + rightChild->f; // 频率为子节点频率之和
        l = leftChild;
        r = rightChild;
    }
};

// 优先队列的自定义比较器
// 用于构建小顶堆 (Min-Heap)，频率小的节点优先级高
struct C
{
    bool operator()(N* a, N* b)
    {
        // 如果 a 的频率大于 b 的频率，那么 a 的优先级更低，排在后面
        // 这样 std::priority_queue 就会把频率最小的放在 top()
        return a->f > b->f;
    }
};

// 全局哈希表，用于存储字符及其对应的哈夫曼编码
std::map<char, std::string> h; // huffman_codes_map

// 递归函数：生成哈夫曼编码
// n: 当前节点
// s: 当前节点对应的编码前缀
void g(N* n, std::string s) // generate_codes
{
    // 如果节点为空，直接返回
    if (n == nullptr)
    {
        return;
    }

    // 如果是叶子节点 (即代表一个字符的节点)
    if (n->c != '\0') // '\0' 表示内部节点
    {
        h[n->c] = s; // 将当前字符及其编码存入全局映射
    }

    // 遍历左子树，路径加 '0'
    g(n->l, s + "0");
    // 遍历右子树，路径加 '1'
    g(n->r, s + "1");
}

// 函数：构建哈夫曼树
// m: 存储字符频率的映射 (map<char, int>)
N* b(std::map<char, int>& m) // build_huffman_tree
{
    // 创建一个优先队列，存储 N* 指针，使用自定义比较器 C
    // std::vector<N*> 是 priority_queue 的底层容器
    std::priority_queue<N*, std::vector<N*>, C> pq;

    // 遍历字符频率映射，为每个字符创建叶子节点并加入优先队列
    for (auto const& [key, val] : m)
    {
        pq.push(new N(key, val));
    }

    // 特殊情况处理：如果只有一个字符，哈夫曼树可能只有一个节点
    // 为了保证树结构完整（哪怕是退化的），我们给它一个虚拟父节点
    if (pq.size() == 1)
    {
        N* u = pq.top(); // 取出唯一的字符节点
        pq.pop();
        N* p = new N('\0', u->f); // 创建一个虚拟父节点，频率相同
        p->l = u; // 将原节点作为父节点的左孩子
        h[u->c] = "0"; // 约定其编码为 "0"
        return p; // 返回这个虚拟父节点作为根
    }

    // 当优先队列中节点数量大于1时，持续合并
    while (pq.size() > 1)
    {
        // 取出频率最小的两个节点
        N* x = pq.top(); // 第一个最小频率节点
        pq.pop();
        N* y = pq.top(); // 第二个最小频率节点
        pq.pop();

        // 创建一个新的内部节点，将 x 和 y 作为其左右孩子
        N* z = new N(x, y);

        // 将新节点放入优先队列
        pq.push(z);
    }

    // 循环结束后，优先队列中剩下的最后一个节点就是哈夫曼树的根节点
    return pq.top();
}

// 函数：解码二进制字符串
// r: 哈夫曼树的根节点 (root)
// e: 待解码的二进制字符串 (encoded_string)
std::string d(N* r, const std::string& e) // decode_string
{
    std::string s = ""; // 存储解码后的字符串 (decoded_string)
    N* c = r;           // 当前遍历节点，初始化为根节点 (current_node)

    // 遍历编码字符串的每一个比特
    for (char b : e) // bit
    {
        if (b == '0')
        {
            c = c->l; // 遇到 '0' 走向左子树
        }
        else
        {
            c = c->r; // 遇到 '1' 走向右子树
        }

        // 如果当前节点是叶子节点 (即代表一个字符)
        if (c->c != '\0') // '\0' 表示内部节点
        {
            s += c->c; // 将字符添加到解码结果中
            c = r;     // 重置当前节点为根节点，准备解码下一个字符
        }
    }
    return s;
}

// 函数：释放哈夫曼树占用的内存 (free_tree)
void f(N* n)
{
    if (n == nullptr)
    {
        return;
    }
    f(n->l); // 递归释放左子树
    f(n->r); // 递归释放右子树
    delete n; // 释放当前节点
}

int main()
{
    // 示例字符频率表
    std::map<char, int> m; // frequencies_map
    m['A'] = 5;
    m['B'] = 9;
    m['C'] = 12;
    m['D'] = 13;
    m['E'] = 16;
    m['F'] = 45;
    // 也可以从用户输入或文件中读取频率

    std::cout << "--- 哈夫曼编码演示 ---" << std::endl;

    // 1. 构建哈夫曼树
    std::cout << "正在构建哈夫曼树..." << std::endl;
    N* r = b(m); // root

    // 2. 生成哈夫曼编码
    std::cout << "正在生成哈夫曼编码..." << std::endl;
    g(r, ""); // 从根节点开始，初始编码为空字符串

    // 打印生成的编码
    std::cout << "生成的哈夫曼编码表：" << std::endl;
    for (auto const& [key, val] : h)
    {
        std::cout << "  '" << key << "': " << val << std::endl;
    }

    // 3. 编码示例字符串
    std::string original_text = "FACE";
    std::string encoded_text = "";
    std::cout << "\n原始文本: " << original_text << std::endl;
    for (char c_char : original_text)
    {
        encoded_text += h[c_char];
    }
    std::cout << "编码后文本: " << encoded_text << std::endl;

    // 4. 解码示例二进制串
    std::string encoded_input = "1111001100101"; // 这是例题2中的编码
    std::cout << "\n待解码二进制串: " << encoded_input << std::endl;
    std::string decoded_text = d(r, encoded_input);
    std::cout << "解码后文本: " << decoded_text << std::endl;

    // 5. 内存清理 (非常重要！)
    f(r); // 释放哈夫曼树占用的内存

    std::cout << "\n演示结束。" << std::endl;

    return 0;
}
```

