### 例题 2：最大的油田 🛢️
**题目描述**：
在 $n \times m$ 的地图中，`*` 代表空地，`@` 代表油田。如果两个油田相邻（含 8 个方向），则属于同一个油藏。求面积最大的油藏包含多少个 `@`。

**思路分析**：
1.  基本框架与例题 1 相同。
2.  在 BFS 内部增加一个计数器 `cnt`，每当一个点入队，`cnt++`。
3.  BFS 结束后，用 `cnt` 更新全局最大值 `ans = max(ans, cnt)`。
4.  方向数组改为 8 个方向。

**代码实现**：
```cpp
#include <bits/stdc++.h>
using namespace std;

int n, m, ans;
char a[105][105];
bool v[105][105];
int dx[] = {-1, 1, 0, 0, -1, -1, 1, 1};
int dy[] = {0, 0, -1, 1, -1, 1, -1, 1};

int bfs(int sx, int sy)
{
    int cnt = 0;
    queue<pair<int, int>> q;
    q.push({sx, sy});
    v[sx][sy] = 1;

    while (!q.empty())
    {
        pair<int, int> curr = q.front();
        q.pop();
        cnt++; // 统计面积

        for (int i = 0; i < 8; i++)
        {
            int nx = curr.first + dx[i];
            int ny = curr.second + dy[i];

            if (nx >= 1 && nx <= n && ny >= 1 && ny <= m && a[nx][ny] == '@' && !v[nx][ny])
            {
                v[nx][ny] = 1;
                q.push({nx, ny});
            }
        }
    }
    return cnt;
}

int main()
{
    cin >> n >> m;
    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            cin >> a[i][j];
        }
    }

    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            if (a[i][j] == '@' && !v[i][j])
            {
                ans = max(ans, bfs(i, j));
            }
        }
    }

    cout << ans << endl;
    return 0;
}
```

