## 代码实现模板

为了方便同学们理解和快速应用，这里提供多源BFS和0-1 BFS的通用代码模板。

### 多源BFS 模板

```cpp
#include <bits/stdc++.h>

using namespace std;

const int INF = 0x3f3f3f3f; // 表示无穷大，用于初始化距离
const int MAXN = 1005;      // 最大网格尺寸

int n, m;                   // 网格的行数和列数
char g[MAXN][MAXN];         // 存储地图
int d[MAXN][MAXN];          // 存储距离（或时间）

// 定义方向数组：上、下、左、右
int dx[] = {-1, 1, 0, 0};
int dy[] = {0, 0, -1, 1};

// 检查坐标是否在网格范围内
bool isValid(int x, int y)
{
    return x >= 0 && x < n && y >= 0 && y < m;
}

void multiSourceBFS()
{
    queue<pair<int, int>> q; // BFS队列，存储格子坐标

    // 1. 初始化所有距离为-1（或INF），表示未访问/不可达
    for (int i = 0; i < n; ++i)
    {
        for (int j = 0; j < m; ++j)
        {
            d[i][j] = -1; // 或 INF
        }
    }

    // 2. 将所有源点入队，并设置它们的初始距离为0
    for (int i = 0; i < n; ++i)
    {
        for (int j = 0; j < m; ++j)
        {
            // 假设源点是 'S' 或者满足某个条件
            if (g[i][j] == 'S') // 示例：所有'S'都是源点
            {
                q.push({i, j});
                d[i][j] = 0;
            }
        }
    }

    // 3. BFS核心循环
    while (!q.empty())
    {
        pair<int, int> current = q.front();
        q.pop();

        int x = current.first;
        int y = current.second;

        // 遍历所有相邻的格子
        for (int i = 0; i < 4; ++i)
        {
            int nx = x + dx[i];
            int ny = y + dy[i];

            // 检查：1. 坐标是否合法 2. 是否满足移动条件 3. 是否未被访问过
            if (isValid(nx, ny) && g[nx][ny] != '#' && d[nx][ny] == -1) // 示例：不能是障碍物'#'且未访问
            {
                d[nx][ny] = d[x][y] + 1; // 更新距离
                q.push({nx, ny});       // 新节点入队
            }
        }
    }
}

int main()
{
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    // 读取 n, m 和地图 g
    // ...

    multiSourceBFS();

    // 输出结果 d 数组
