## 代码实现模板

### 通用 BFS 扩展模板（带层数记录与多源支持）
```cpp
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 100005;
int head[MAXN], e[MAXN * 2], nxt[MAXN * 2], idx;
int d[MAXN]; // 存储距离/层数
int q[MAXN]; // 原生数组模拟队列

void add(int u, int v) 
{
    e[++idx] = v;
    nxt[idx] = head[u];
    head[u] = idx;
}

void solve() 
{
    int hh = 0, tt = -1;

    // 1. 初始化距离为 -1 (代表未访问)
    memset(d, -1, sizeof(d));

    // 2. 多源起点入队 (如果是单源，只放一个)
    // d[start_node] = 0;
    // q[++tt] = start_node;

    // 3. 核心循环
    while (hh <= tt) 
    {
        int u = q[hh++];

        for (int i = head[u]; i; i = nxt[i]) 
        {
            int v = e[i];
            if (d[v] == -1) // 未访问
            {
                d[v] = d[u] + 1; // 更新层数
                q[++tt] = v;     // 入队
            }
        }
    }
}
```

