// d[u] 存储节点 u 的度数（有多少个邻居）
int g[MAXN][MAXN]; // 存储邻接节点，MAXN的第二个维度表示最大度数，这里简化为MAXN
int d[MAXN];       // d[u] 存储节点 u 当前的邻居数量

// 访问标记数组，visited[u] 为 true 表示节点 u 已经被访问过
bool visited[MAXN];

// DFS 函数
// 参数 u: 当前正在访问的节点
void dfs(int u)
{
    visited[u] = true; // 1. 标记当前节点 u 已被访问

    // 2. 在这里可以进行对节点 u 的操作，例如：
