        std::cin >> coin[i];
    }

    // dp[j] 表示能凑出 j 元钱的最大值（其实就是 j），
    // 这里的dp[j]表示用前i个硬币能凑出的最接近j的钱数。
    // 如果dp[j]初始化为0，则表示默认不能凑出。
    // 如果dp[j]初始化为-1，表示不能凑出，需要特殊处理0。

    // 为了简单，我们让dp[j]表示“容量为j时，能凑出的最大钱数”，
    // 这样，每个硬币的重量和价值都是其面值。
    // dp数组初始化为0即可。

    for (int i = 1; i <= n; ++i) {
        for (int j = M; j >= coin[i]; --j) {
            dp[j] = std::max(dp[j], dp[j - coin[i]] + coin[i]);
        }
    }

    // 最终dp[M]可能不是M，而是小于M的一个最大值
    std::cout << dp[M] << std::endl;

    return 0;
}
```

