### 参考答案

**1. 零食采购**
```cpp
#include <bits/stdc++.h>
using namespace std;
const int MAXM = 1005;
const int MAXN = 105;
int p[MAXN]; // 价格 (重量)
int t[MAXN]; // 美味值 (价值)
int f[MAXM]; // dp数组
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n, m;
    cin >> n >> m;
    for (int i = 1; i <= n; ++i) {
        cin >> p[i] >> t[i];
    }
    // f数组默认初始化为0
    for (int i = 1; i <= n; ++i) {
        for (int j = p[i]; j <= m; ++j) { // 正向循环
            f[j] = max(f[j], f[j - p[i]] + t[i]);
        }
    }
    cout << f[m] << endl;
    return 0;
}
```

**2. 凑数字**
```cpp
#include <bits/stdc++.h>
using namespace std;
const int MAXT = 10005;
const int MAXN = 105;
int a[MAXN]; // 数字值 (重量)
bool f[MAXT]; // f[j] 表示是否能凑出和为 j
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n, t;
    cin >> n >> t;
    for (int i = 1; i <= n; ++i) {
        cin >> a[i];
    }
    f[0] = true; // 凑出和为0是可能的 (不选任何数字)
    for (int i = 1; i <= n; ++i) {
        for (int j = a[i]; j <= t; ++j) { // 正向循环
            f[j] = f[j] || f[j - a[i]]; // f[j] 为真，如果原来就能凑出 j，或者 f[j-a[i]] 能凑出
        }
    }
    if (f[t]) {
        cout << "YES" << endl;
    } else {
        cout << "NO" << endl;
    }
    return 0;
}
```

**3. 最少钱币凑和**
```cpp
#include <bits/stdc++.h>
using namespace std;
const int MAXM = 10005;
const int MAXN = 105;
const int INF = 0x3f3f3f3f; // 表示一个很大的数，无穷大
int v[MAXN]; // 钱币面值
int f[MAXM]; // f[j] 表示凑出金额 j 所需的最少钱币数
int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n, m;
    cin >> n >> m;
    for (int i = 1; i <= n; ++i) {
        cin >> v[i];
    }
    // 初始化 f 数组
    // f[0] = 0 (凑出金额0需要0枚钱币)
    // f[j > 0] = INF (其他金额初始为无法凑出，需要无穷多枚钱币)
    for (int j = 1; j <= m; ++j) {
        f[j] = INF;
    }
    f[0] = 0;

    for (int i = 1; i <= n; ++i) {
        for (int j = v[i]; j <= m; ++j) { // 正向循环
            if (f[j - v[i]] != INF) { // 只有当 f[j-v[i]] 是可达的时候才更新
                f[j] = min(f[j], f[j - v[i]] + 1);
            }
        }
    }
    if (f[m] == INF) {
        cout << -1 << endl;
    } else {
        cout << f[m] << endl;
    }
    return 0;
}
```

